/**
 * @param {number[]} nums
 * @param {number} k
 * @return {number}
 */
function solve(nums, k) {
    const n = nums.length;
    if (n === 0) {
        return 0;
    }

    // DP state:
    // dp_up[i]: Maximum score of a valid alternating subsequence ending at index i,
    // where nums[i] is *greater* than the previous element (i.e., it's a peak or the start of an up-trend).
    // dp_down[i]: Maximum score of a valid alternating subsequence ending at index i,
    // where nums[i] is *smaller* than the previous element (i.e., it's a valley or the start of a down-trend).

    // Initialize with the value itself, as a sequence of length 1 is always valid.
    const dp_up = new Array(n).fill(0);
    const dp_down = new Array(n).fill(0);

    for (let i = 0; i < n; i++) {
        dp_up[i] = nums[i];
        dp_down[i] = nums[i];

        // Iterate over all previous indices j that satisfy the distance constraint: i - j >= k
        for (let j = 0; j < i - k + 1; j++) {
            // 1. Try to extend a sequence ending at j with nums[i] such that nums[i] > nums[j] (Up move)
            // This means the sequence ending at j must have ended with a 'down' move (or be length 1).
            if (nums[i] > nums[j]) {
                // New score = (Max score ending at j with a down move) + nums[i]
                // We take max(current dp_up[i], dp_down[j] + nums[i])
                dp_up[i] = Math.max(dp_up[i], dp_down[j] + nums[i]);
            }

            // 2. Try to extend a sequence ending at j with nums[i] such that nums[i] < nums[j] (Down move)
            // This means the sequence ending at j must have ended with an 'up' move (or be length 1).
            if (nums[i] < nums[j]) {
                // New score = (Max score ending at j with an up move) + nums[i]
                // We take max(current dp_down[i], dp_up[j] + nums[i])
                dp_down[i] = Math.max(dp_down[i], dp_up[j] + nums[i]);
            }
        }
    }

    let maxScore = 0;
    for (let i = 0; i < n; i++) {
        maxScore = Math.max(maxScore, dp_up[i], dp_down[i]);
    }

    return maxScore;
}

